mapper.select:
SELECT l.id, l.registration_id, l.patient_id, p.patient_name,
       l.lab_type, l.lab_name, l.result, l.reference_range, l.fee, l.status, l.lab_time
FROM laboratory l
LEFT JOIN patient p ON l.patient_id = p.id

    AND l.registration_id = #{registrationId}
    AND l.patient_id = #{patientId}
    AND l.registration_id IN (SELECT r.id FROM registration r WHERE r.doctor_id = #{doctorId})
    AND l.status = #{status}

ORDER BY l.lab_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM laboratory l

    AND l.registration_id = #{registrationId}
    AND l.patient_id = #{patientId}
    AND l.registration_id IN (SELECT r.id FROM registration r WHERE r.doctor_id = #{doctorId})
    AND l.status = #{status}
